#!/usr/bin/env bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

# Requires dataset generated by synthetic-scale step.
node_out="$(node "$SCRIPT_DIR/node_validator.js")"
py_out="$(python3 "$SCRIPT_DIR/python_validator.py")"

node_total="$(printf '%s\n' "$node_out" | awk -F= '/^node_total=/{print $2}')"
node_parse="$(printf '%s\n' "$node_out" | awk -F= '/^node_parse_rejected=/{print $2}')"
node_checks="$(printf '%s\n' "$node_out" | awk -F= '/^node_checks_rejected=/{print $2}')"
node_admitted="$(printf '%s\n' "$node_out" | awk -F= '/^node_admitted=/{print $2}')"

py_total="$(printf '%s\n' "$py_out" | awk -F= '/^python_total=/{print $2}')"
py_parse="$(printf '%s\n' "$py_out" | awk -F= '/^python_parse_rejected=/{print $2}')"
py_checks="$(printf '%s\n' "$py_out" | awk -F= '/^python_checks_rejected=/{print $2}')"
py_admitted="$(printf '%s\n' "$py_out" | awk -F= '/^python_admitted=/{print $2}')"

consistent="false"
if [[ "$node_total" == "$py_total" && "$node_parse" == "$py_parse" && "$node_checks" == "$py_checks" && "$node_admitted" == "$py_admitted" ]]; then
  consistent="true"
fi

echo "Experiment 5 (cross-validator consistency)"
echo "Node total: $node_total"
echo "Node parse rejected: $node_parse"
echo "Node checks rejected: $node_checks"
echo "Node admitted: $node_admitted"
echo "Python total: $py_total"
echo "Python parse rejected: $py_parse"
echo "Python checks rejected: $py_checks"
echo "Python admitted: $py_admitted"
echo "Consistent: $consistent"

if [[ "$consistent" != "true" ]]; then
  exit 1
fi
